-- ═══════════════════════════════════════════════════════════════════════════════
-- ladx.lua — game module for the Archipelago BizHawk connector.
--            The Legend of Zelda: Link's Awakening DX (Game Boy Color)
--
-- STATUS: location DETECTION + goal are REAL and SOURCE-DERIVED from the official
-- AP world worlds/ladx (LinksAwakeningClient.py + Tracker.py + Locations.py +
-- LADXR/checkMetadata.py, main branch). The 254-entry location table below was
-- GENERATED by a Python script that imports the real checkMetadataTable and
-- replicates, byte-for-byte, BOTH source functions:
--   • Locations.py get_locations_to_id()  → ap_id = BASE_ID(10000000) + main + sub
--   • Tracker.py LocationTracker.__init__  → (address, mask, alternateAddress)
-- so the ids AND the detection bytes/masks are exact, not hand-copied. Loads
-- crash-free on any ROM; self-disables when the cartridge is not a running LADX.
--
-- MEMORY MODEL (BizHawk Game Boy)
-- ────────────────────────────────
--   The LADX AP client (LinksAwakeningClient.py) is a RetroArch/BizHawk client
--   that reads Game Boy memory through the "System Bus" domain — the AP-shipped
--   connector_ladx_bizhawk.lua reads EVERY address via
--   memory.read_bytes_as_array(addr, len, "System Bus") (its own comment: WRAM vs
--   ROM differ between GB cores, so the System Bus is the portable choice). We do
--   the same: all addresses here are GB System-Bus addresses.
--     • WRAM check flags live at 0xD800..0xDDF4 (one byte per room/event; a check
--       is "done" when (byte & mask) > 0; a few have a second "alternate" byte and
--       the source ORs the two — replicated).
--     • Game-state / safety / victory live in WRAM/HRAM (constants below, taken
--       verbatim from LAClientConstants).
--     • ROM header 0x0134 holds the AP-written slot name (GB cartridge title field;
--       the client's reset_auth reads 0x0134 for 12 bytes as its auth) — used here
--       as a soft "this is an AP-patched cart" gate so a blank/vanilla cart idles.
--
-- DETECTION GATE (mirrors LinksAwakeningClient.RAGameboy.check_safe_gameplay)
--   poll() reports a check only when the game is in a SAFE PLAYING state:
--     • the 4 safety bytes at 0xC0FB..0xC0FE (wCheckAddress = 0xC0FF-4) are all 0
--       (the client's WRamSafetyValue guard against reading garbage), AND
--     • wGameplayType (0xDB95) is in [0x06, 0x1A] (MinGameplayValue..MaxGameplayValue)
--       OR == 0x01 (victory) — exactly the client's gameplay window.
--   This keeps the title screen / transitions / save-corrupt frames from ever
--   reporting checks, identical to the upstream client.
--
-- GOAL (mirrors LinksAwakeningClient.is_victory)
--   wGameplayType (0xDB95) == 0x01  →  the game is on the victory/credits state.
--
-- receive_item(): DOCUMENTED NO-OP (see the note at the bottom). LADX's
-- items_handling is 0b101 (remote items): the game does NOT self-grant remote
-- multiworld items — the upstream client delivers them with a guarded
-- write handshake (wLinkGiveItem/wLinkStatusBits/wRecvIndex, spin-until-safe,
-- only after the player's first check). That write path is exactly the piece
-- that needs in-emulator verification before it is trusted, so it is GATED OFF
-- here rather than shipped unverified (a wrong write could corrupt the save).
-- Check reporting + goal are fully live regardless.
--
-- MODULE CONTRACT (called by bizhawk_ap_connector.lua)
--   M.init(ctx) / M.poll() -> {ids} / M.is_goal_complete() -> bool /
--   M.receive_item(item_id, meta)
-- ═══════════════════════════════════════════════════════════════════════════════

local M = {}
M.name = "ladx"

local ADDRESSES_VERIFIED = true   -- table generated from worlds/ladx source

-- ── Memory domain ─────────────────────────────────────────────────────────────
-- The AP connector reads GB memory via the System Bus (portable across GB cores).
local SYSBUS = "System Bus"

-- ── Addresses / constants (LinksAwakeningClient.py LAClientConstants) ─────────
local BASE_ID            = 10000000     -- worlds/ladx/Common.py BASE_ID
local SLOT_NAME_ADDR     = 0x0134       -- ROM header: AP-written slot name (auth)
local SLOT_NAME_LEN      = 12

local WGAMEPLAY_TYPE     = 0xDB95       -- main game-state byte
local SAFETY_ADDR        = 0xC0FF - 0x4 -- wCheckAddress (0xC0FB); 4 bytes, all 0
local SAFETY_SIZE        = 0x4
local MIN_GAMEPLAY       = 0x06         -- MinGameplayValue
local MAX_GAMEPLAY       = 0x1A         -- MaxGameplayValue
local VICTORY_VALUE      = 0x01         -- is_victory: wGameplayType == 1

-- Location flag window in WRAM (covers every LOC address + alternates).
local LOC_LOW            = 0xD800
local LOC_HIGH           = 0xDDF4

