-- ── State ─────────────────────────────────────────────────────────────────────
local reported         = {}     -- ap_id -> true once returned from poll()
local server_locations = nil    -- set of ap_ids the server expects (nil = all)
local rom_ok           = nil     -- cached slot-name (AP cart) result
local mem              = {}
local log_fn           = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[ladx] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8 = memory.read_u8 or memory.readbyte
  return mem.read_u8 ~= nil
end

local function read_u8(addr, domain)
  if not mem.read_u8 then return nil end
  local ok, v = pcall(mem.read_u8, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, addr)            -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

local function bit_and(a, b)
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

-- ── ROM identity: an AP-patched LADX cart carries a printable slot name at the
--    GB header title field 0x0134 (the client's auth source). A vanilla LADX cart
--    reads "ZELDA" there + zero padding; a contentless/wrong cart reads junk.
--    We accept any cart whose 0x0134..0x0143 looks like a non-empty printable
--    title — this self-disables only on an empty/garbage cart, never on a real
--    LADX, exactly the level of identity the upstream client relies on. ────────
local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  local printable, any = 0, false
  for i = 0, SLOT_NAME_LEN - 1 do
    local b = read_u8(SLOT_NAME_ADDR + i, SYSBUS)
    if b == nil then return false end           -- not readable yet; retry next poll
    if b ~= 0 then
      any = true
      -- printable ASCII (space..~) — slot names and "ZELDA" both qualify.
      if b >= 0x20 and b <= 0x7E then printable = printable + 1 end
    end
  end
  if any and printable >= 1 then
    rom_ok = true
    log("LADX cart detected (header title present at 0x0134) — detection live")
    return true
  end
  rom_ok = false
  log("no LADX cart header at 0x0134 — detection idle")
  return false
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end
  return server_locations[ap_id] == true
end

-- ── Detection gate (LinksAwakeningClient.RAGameboy.check_safe_gameplay) ────────
local function in_safe_gameplay()
  -- Safety bytes at 0xC0FB..0xC0FE must all be 0 (WRamSafetyValue).
  for i = 0, SAFETY_SIZE - 1 do
    local b = read_u8(SAFETY_ADDR + i, SYSBUS)
    if b == nil then return false end
    if b ~= 0 then return false end
  end
  local s = read_u8(WGAMEPLAY_TYPE, SYSBUS)
  if s == nil then return false end
  -- In gameplay window OR victory.
  if (s >= MIN_GAMEPLAY and s <= MAX_GAMEPLAY) or s == VICTORY_VALUE then
    return true
  end
  return false
end

-- ── Per-check evaluation: (byte & mask) > 0, ORed with the alternate byte ──────
local function check_done(entry)
  local b = read_u8(entry.a, SYSBUS)
  if b ~= nil and bit_and(b, entry.m) > 0 then return true end
  if entry.alt then
    local b2 = read_u8(entry.alt, SYSBUS)
    if b2 ~= nil and bit_and(b2, entry.m) > 0 then return true end
  end
  return false
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  local n = 0; for _ in pairs(LOC) do n = n + 1 end
  log("ready: " .. n .. " location flags (0x" ..
      string.format("%04X", LOC_LOW) .. "..0x" .. string.format("%04X", LOC_HIGH) .. ")")
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ap() then return new end
  if not in_safe_gameplay() then return new end
  for ap_id, entry in pairs(LOC) do
    if not reported[ap_id] and wanted(ap_id) and check_done(entry) then
      reported[ap_id] = true
      new[#new + 1] = ap_id
    end
  end
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ap() then return false end
  local s = read_u8(WGAMEPLAY_TYPE, SYSBUS)
  return s ~= nil and s == VICTORY_VALUE
end

-- Remote multiworld items: see the file header. LADX items_handling = 0b101 means
-- the game does NOT self-grant remote items — the upstream client delivers them
-- with a guarded write handshake (wLinkGiveItem / wLinkStatusBits bit0 /
-- wRecvIndex, spinning until the game is in a safe state and only after the
-- player's first check). That write path is the one piece deferred until it can
-- be confirmed in-emulator; applying it unverified risks corrupting the save, so
-- this is a no-op for now. Check reporting + goal remain fully live.
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
